using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change 1: Discriminator property renamed from "Discriminator" to "$type".
            // Keep old property name so existing documents and raw SQL
            // (e.g. WHERE c.Discriminator = 'Blog') continue to work.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change 2: id value no longer prefixed with discriminator.
            // Existing documents have id = "Blog|{key}". Restore old format.
            entity.Property<string>("__id")
                .ToJsonProperty("id")
                .HasValueGenerator<LegacyIdValueGenerator>();

            // Breaking change 3: HasIndex now throws on the Cosmos provider.
            // Previously it was silently ignored — remove the call.
            // REMOVED: entity.HasIndex(b => b.Name);
        });
    }
}

/// <summary>
/// Restores the EF Core 8 Cosmos id format: "{Discriminator}|{Key}".
/// </summary>
class LegacyIdValueGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;

    public override string Next(EntityEntry entry)
    {
        var entityType = entry.Metadata;
        var discriminator = entityType.GetDiscriminatorValue()?.ToString()
            ?? entityType.ShortName();
        var primaryKey = entityType.FindPrimaryKey()!;
        var keyValues = string.Join("|",
            primaryKey.Properties.Select(p => entry.Property(p).CurrentValue));
        return $"{discriminator}|{keyValues}";
    }
}

class Blog { public string Id { get; set; } public string Name { get; set; } }

